import math
import numpy as np


def constant_schedule(step, lr=0.01, **kwargs):
    """Constant learning rate: returns lr for every step."""
    return float(lr)


def step_decay_schedule(step, lr=0.1, step_size=100, gamma=0.1, **kwargs):
    """Step decay: lr * gamma ** floor(step / step_size)."""
    return float(lr) * (float(gamma) ** (int(step) // int(step_size)))


def cosine_schedule(step, lr=0.01, total_steps=1000, lr_min=1e-5, **kwargs):
    """Cosine annealing from lr (at step 0) down to lr_min (at step total_steps)."""
    if step >= total_steps:
        return float(lr_min)
    cos = math.cos(math.pi * step / total_steps)
    return float(lr_min) + 0.5 * (float(lr) - float(lr_min)) * (1.0 + cos)


def warmup_cosine_schedule(step, lr=0.01, total_steps=1000, warmup_steps=100,
                           lr_min=1e-5, **kwargs):
    """Linear warmup for the first warmup_steps, then cosine decay to lr_min."""
    if total_steps <= warmup_steps:
        return float(lr) * (step / max(warmup_steps, 1))
    if step < warmup_steps:
        return float(lr) * step / warmup_steps
    progress = (step - warmup_steps) / (total_steps - warmup_steps)
    cos = math.cos(math.pi * progress)
    return float(lr_min) + 0.5 * (float(lr) - float(lr_min)) * (1.0 + cos)


def one_cycle_schedule(step, lr=0.01, total_steps=1000, **kwargs):
    """1cycle policy: ramp lr/25 -> lr over the first half, then lr -> lr/10000."""
    lr = float(lr)
    mid = max(total_steps // 2, 1)
    if step < mid:
        return (lr / 25.0) + (lr - lr / 25.0) * step / mid
    progress = (step - mid) / max(total_steps - mid, 1)
    return lr * (1.0 - progress) + (lr / 10000.0) * progress


def lr_curve(schedule_fn, total_steps, lr=0.01, **kwargs):
    """Sample a schedule over every step into a 1D np.ndarray of length total_steps."""
    vals = [schedule_fn(s, lr=lr, total_steps=total_steps, **kwargs)
            for s in range(total_steps)]
    return np.asarray(vals, dtype=float)
